export function TypographyScale(): React.ReactElement {
    const sizes = [
        { name: 'xs', value: '12px' },
        { name: 'sm', value: '14px' },
        { name: 'base', value: '16px' },
        { name: 'lg', value: '18px' },
        { name: 'xl', value: '20px' },
        { name: '2xl', value: '24px' },
        { name: '3xl', value: '30px' },
        { name: '4xl', value: '36px' },
        { name: '5xl', value: '48px' },
        { name: '6xl', value: '60px' },
    ];

    return (
        <div className="my-6 space-y-6">
            {sizes.map((size) => (
                <div key={size.name} className="flex items-baseline gap-4">
                    <span className="w-16 text-right font-mono text-xs text-fd-muted-foreground">
                        {size.name}
                    </span>
                    <span style={{ fontSize: size.value }}>
                        The quick brown fox jumps over the lazy dog
                    </span>
                    <span className="font-mono text-xs text-fd-muted-foreground">
                        {size.value}
                    </span>
                </div>
            ))}
        </div>
    );
}
